update course_schedule
teacher_id = #{teacherId}, classroom_id = #{classroomId}, class_ids = #{classIds}, week_day = #{weekDay}, start_section = #{startSection}, end_section = #{endSection}, week_range = #{weekRange}, update_time = now()
where id = #{id}

mapper.select:
select cs.id, cs.semester_id, s.semester_name, cs.course_id, c.course_name, t.id as teacher_id, t.teacher_name,
       cr.id as classroom_id, cr.classroom_name, cs.class_ids, cs.week_day, cs.start_section, cs.end_section, cs.week_range,
       cs.create_time, cs.update_time
from course_schedule cs
left join semester s on cs.semester_id = s.id
left join course c on cs.course_id = c.id
left join teacher t on cs.teacher_id = t.id
left join classroom cr on cs.classroom_id = cr.id

    cs.semester_id = #{semesterId}
    and cs.course_id = #{courseId}
    and cs.teacher_id = #{teacherId}
    and cs.classroom_id = #{classroomId}
    and cs.week_day = #{weekDay}

order by cs.create_time desc

select cs.id as course_schedule_id, c.course_name, t.teacher_name, cr.classroom_name, cs.week_day, cs.start_section, cs.end_section, cs.week_range from course_schedule cs left join course c on cs.course_id = c.id left join teacher t on cs.teacher_id = t.id left join classroom cr on cs.classroom_id = cr.id
cs.semester_id = #{semesterId} and cs.teacher_id = #{userId}
and (
FIND_IN_SET(#{classId}, cs.class_ids)
)
order by cs.week_day asc, cs.start_section asc

select cs.id, cs.semester_id, s.semester_name, cs.course_id, c.course_name, t.id as teacher_id, t.teacher_name,
       cr.id as classroom_id, cr.classroom_name, cs.class_ids, cs.week_day, cs.start_section, cs.end_section, cs.week_range,
       cs.create_time, cs.update_time
from course_schedule cs
left join semester s on cs.semester_id = s.id
left join course c on cs.course_id = c.id
left join teacher t on cs.teacher_id = t.id
left join classroom cr on cs.classroom_id = cr.id
where cs.semester_id = #{semesterId}
and cs.teacher_id = #{teacherId}
and cs.week_day = #{weekDay}
and not (cs.end_section < #{startSection} or cs.start_section > #{endSection})
and cs.id != #{excludeId}

